WHERE ((([ORDER DETAIL].Start) Is Null Or ([ORDER DETAIL].Start)=#4/1/2013# Or ([ORDER DETAIL].Start)=#9/1/2013# Or ([ORDER DETAIL].Start)=#9/1/2014#) AND (([ORDER DETAIL].[Prod Type])="Spray" Or ([ORDER DETAIL].[Prod Type])="PPHM")) OR ((([ORDER DETAIL].Start) Is Null Or ([ORDER DETAIL].Start)=#4/1/2013# Or ([ORDER DETAIL].Start)=#9/1/2013# Or ([ORDER DETAIL].Start)=#9/1/2014#) AND (([ORDER DETAIL].[Prod Type])="Hide") AND (([ORDER DETAIL].Description) Is Null));

SELECT CUSTOMER.Source, ORDER.[Proposal Date], CUSTOMER.Lname, ORDER.OID, CUSTOMER.CID
FROM CUSTOMER INNER JOIN [ORDER] ON CUSTOMER.CID = ORDER.CID
WHERE (((CUSTOMER.Source) Like "*yp*") AND ((ORDER.[Proposal Date])>#1/1/2017#) AND ((CUSTOMER.CID)>8317));

SELECT DISTINCTROW CUSTOMER.*
FROM (CUSTOMER INNER JOIN [ORDER] ON CUSTOMER.CID = ORDER.CID) INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID
WHERE (([ORDER DETAIL].[Prod Type]="PPHM"));

SELECT DISTINCTROW CUSTOMER.Title, CUSTOMER.Fname, CUSTOMER.Lname, CUSTOMER.Company, CUSTOMER.Street1, CUSTOMER.City, CUSTOMER.State, CUSTOMER.Source, CUSTOMER.Map, CUSTOMER.Grid, CUSTOMER.Phone, CUSTOMER.Fax, CUSTOMER.[Evening Phone], ORDER.OID, ORDER.CID, ORDER.[Work Street], ORDER.[Work City], ORDER.[Work State], ORDER.[Work Zip], [ORDER DETAIL].[Line No], [ORDER DETAIL].[Prod Type], [ORDER DETAIL].Price, [ORDER DETAIL].Plant, [ORDER DETAIL].Location, [ORDER DETAIL].Accept, [ORDER DETAIL].Start, [ORDER DETAIL].End, [ORDER DETAIL].Pest
FROM (CUSTOMER INNER JOIN [ORDER] ON CUSTOMER.CID = ORDER.CID) INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID
WHERE (([ORDER DETAIL].[Prod Type]="Spray"));

SELECT ORDER.[Accept Date], [ORDER DETAIL].[Accepted Date], EVENT.Complete_Date, EVENT.Bill_Date, EVENT.[Paid Date], EVENT.[Paid Amount], EVENT.[Paid Amount 2], EVENT.[Paid Amount 3], EVENT.[Paid Amount 4], EVENT.[Paid  date 2], EVENT.[Paid date 3], EVENT.[Paid date 4], EVENT.[Paid Date 1], EVENT.[Check Number 1], EVENT.[Check Number 2], EVENT.[Check Number 3], EVENT.[Check Number 4], EVENT.[Deposited date], EVENT.[Paid Date], EVENT.[Bill_Date 2], EVENT.[Bill_Date 3], EVENT.[Bill_Date 4]
FROM (CUSTOMER INNER JOIN ([ORDER] INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID) ON CUSTOMER.CID = ORDER.CID) LEFT JOIN EVENT ON ([ORDER DETAIL].[Line No] = EVENT.[Line No]) AND ([ORDER DETAIL].OID = EVENT.OID)
WHERE ((([ORDER DETAIL].[Prod Type])="SPRAY" Or ([ORDER DETAIL].[Prod Type])="PPHM" Or ([ORDER DETAIL].[Prod Type])="LAWN"));

SELECT DISTINCTROW CUSTOMER.Title, CUSTOMER.Fname, CUSTOMER.Lname, CUSTOMER.Street1, CUSTOMER.City, CUSTOMER.[Evening Phone], CUSTOMER.Phone, [ORDER DETAIL].Accept
FROM CUSTOMER INNER JOIN ([ORDER] INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID) ON CUSTOMER.CID = ORDER.CID
WHERE ((([ORDER DETAIL].Accept)=No) AND (([ORDER DETAIL].[Line No])=1 Or ([ORDER DETAIL].[Line No])=3) AND (([ORDER DETAIL].[Prod Type])="Spray"));

SELECT CUSTOMER.Fname, CUSTOMER.Lname, ORDER.OID, [ORDER DETAIL].[Line No], [ORDER DETAIL].[Prod Type], [ORDER DETAIL].Start
FROM (CUSTOMER INNER JOIN [ORDER] ON CUSTOMER.CID = ORDER.CID) INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID
WHERE ((([ORDER DETAIL].[Prod Type])="SPRAY" Or ([ORDER DETAIL].[Prod Type])="PPHM" Or ([ORDER DETAIL].[Prod Type])="IPM DATA") AND (([ORDER DETAIL].Start) Is Null));

SELECT DISTINCTROW [Sequence] AS Expr1, CUSTOMER.CID, CUSTOMER.Lname, CUSTOMER.Street1, CUSTOMER.City, CUSTOMER.Zip, CUSTOMER.Map, CUSTOMER.Grid, CUSTOMER.[Evening Phone], CUSTOMER.[Customer Note], CUSTOMER.Company
FROM CUSTOMER
WHERE (((CUSTOMER.CID)=7494)) OR (((CUSTOMER.CID)=2159)) OR (((CUSTOMER.CID)=6164)) OR (((CUSTOMER.CID)=221)) OR (((CUSTOMER.CID)=7363)) OR (((CUSTOMER.CID)=7543)) OR (((CUSTOMER.CID)=6513)) OR (((CUSTOMER.CID)=7079)) OR (((CUSTOMER.CID)=2132)) OR (((CUSTOMER.CID)=7166)) OR (((CUSTOMER.CID)=5626)) OR (((CUSTOMER.CID)=6751)) OR (((CUSTOMER.CID)=6286)) OR (((CUSTOMER.CID)=6461)) OR (((CUSTOMER.CID)=7622));

SELECT DISTINCTROW CUSTOMER.Lname, ORDER.[Work Street], ORDER.[Work City], ORDER.[Work Map], ORDER.[Work Grid], [ORDER DETAIL].Location, [ORDER DETAIL].Plant, [ORDER DETAIL].Description, [ORDER DETAIL].Price
FROM (CUSTOMER INNER JOIN ([ORDER] INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID) ON CUSTOMER.CID = ORDER.CID) LEFT JOIN EVENT ON ([ORDER DETAIL].[Line No] = EVENT.[Line No]) AND ([ORDER DETAIL].OID = EVENT.OID)
WHERE ((([ORDER DETAIL].Description) Like "*Grind*") AND ((EVENT.Completed)=No Or (EVENT.Completed) Is Null) AND (([ORDER DETAIL].Accept)=Yes));

SELECT CUSTOMER.Lname, [ORDER DETAIL].[Prod Type], [ORDER DETAIL].Pest
FROM (CUSTOMER INNER JOIN [ORDER] ON CUSTOMER.CID = ORDER.CID) INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID
WHERE ((([ORDER DETAIL].[Prod Type])="SPRAY") AND (([ORDER DETAIL].Pest) Like "Tick*1*"));

SELECT DISTINCTROW CUSTOMER.Lname, [ORDER DETAIL].[Prod Type], [ORDER DETAIL].Accept, [ORDER DETAIL].Plant, [ORDER DETAIL].Pest, [ORDER DETAIL].Start, [ORDER DETAIL].End
FROM ((CUSTOMER INNER JOIN [ORDER] ON CUSTOMER.CID = ORDER.CID) INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID) INNER JOIN TREATMENT_DETAIL ON [ORDER DETAIL].[Line No] = TREATMENT_DETAIL.[Line No]
WHERE (([ORDER DETAIL].[Prod Type]="SPRAY") AND ([ORDER DETAIL].Accept=Yes));

SELECT DISTINCTROW [ORDER DETAIL].Price, [ORDER DETAIL].Accept, [ORDER DETAIL].[Line No], EVENT.Completed, [ORDER DETAIL].[Prod Type], EVENT.[Paid in full], EVENT.[To Bill], EVENT.Billed, EVENT.Bill_Date, CUSTOMER.Lname, ORDER.OID
FROM (CUSTOMER INNER JOIN ([ORDER DETAIL] INNER JOIN [ORDER] ON [ORDER DETAIL].OID = ORDER.OID) ON CUSTOMER.CID = ORDER.CID) LEFT JOIN EVENT ON ([ORDER DETAIL].[Line No] = EVENT.[Line No]) AND ([ORDER DETAIL].OID = EVENT.OID)
WHERE ((([ORDER DETAIL].Accept)=True) AND ((EVENT.Completed)=Yes) AND (([ORDER DETAIL].[Prod Type])="WORKSHEET") AND ((EVENT.[Paid in full])=No) AND ((EVENT.[To Bill])=Yes) AND ((EVENT.Billed)=Yes) AND ((EVENT.Bill_Date) Is Null));

SELECT DISTINCTROW CUSTOMER.*, ORDER.*, [ORDER DETAIL].*, [ORDER DETAIL].[Prod Type], ORDER.OID, [ORDER DETAIL].Accept, EVENT.Completed, EVENT.[Prod Type]
FROM (CUSTOMER INNER JOIN ([ORDER] INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID) ON CUSTOMER.CID = ORDER.CID) LEFT JOIN EVENT ON ([ORDER DETAIL].[Line No] = EVENT.[Line No]) AND ([ORDER DETAIL].OID = EVENT.OID)
WHERE (([ORDER DETAIL].[Prod Type]="WORKSHEET") AND ([ORDER DETAIL].Accept=Yes) AND (EVENT.Completed=No) AND (EVENT.[Prod Type]="WORKSHEET"));

SELECT EVENT.[Check Number 1], EVENT.[Check Number 2], EVENT.[Check Number 3], EVENT.[Check Number 4], EVENT.[Paid  date 2], EVENT.[Paid date 3], EVENT.[Paid date 4], EVENT.[Paid Date 1], EVENT.Bill_Date, EVENT.[Paid Date], EVENT.Complete_Date, [ORDER DETAIL].[Accepted Date], [ORDER DETAIL].Accept, EVENT.Event_Date, EVENT.Completed, EVENT.[To Bill], EVENT.Billed, EVENT.[Paid Amount], EVENT.[Paid Amount 2], EVENT.[Paid Amount 3], EVENT.[Paid Amount 4], EVENT.[Paid Total], EVENT.[Paid in full], EVENT.[Billed 2], EVENT.[Billed 3], EVENT.[Billed 4], EVENT.[Bill_Date 2], EVENT.[Bill_Date 3], EVENT.[Bill_Date 4], EVENT.[To be Deposited], EVENT.Deposited, [ORDER DETAIL].Start
FROM ([ORDER] INNER JOIN [ORDER DETAIL] ON ORDER.OID = [ORDER DETAIL].OID) LEFT JOIN EVENT ON ([ORDER DETAIL].[Line No] = EVENT.[Line No]) AND ([ORDER DETAIL].OID = EVENT.OID)
WHERE ((([ORDER DETAIL].[Prod Type])="LAWN" Or ([ORDER DETAIL].[Prod Type])="PPHM" Or ([ORDER DETAIL].[Prod Type])="SPRAY"));

SELECT [ORDER DETAIL].[Prod Type], [ORDER DETAIL].Start, [ORDER DETAIL].OID, [ORDER DETAIL].[Line No]
FROM [ORDER DETAIL]
WHERE ((([ORDER DETAIL].[Prod Type])="PPHM" Or ([ORDER DETAIL].[Prod Type])="Spray") AND (([ORDER DETAIL].Start) Is Null));
